void invert_mapping(float *input, float *output, int npoints, int nfeatures)
{
    int point_id;
#pragma omp parallel for schedule(static)
    for(point_id = 0; point_id < npoints; ++point_id){
        int i;
        for(i = 0; i < nfeatures; ++i){
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
        }
    }
}

void kmeansPoint(float  *features,			
                 int     nfeatures,
                 int     npoints,
                 int     nclusters,
                 int    *membership,
                 float  *clusters,
                 float  *block_clusters,
                 int    *block_deltas)
{
    int total_threads = num_blocks * num_threads;
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int point_id = tid;
        int i, j;
        float min_dist;
        int index = -1;

        #pragma omp for schedule(static)
        for(point_id = 0; point_id < npoints; point_id++) {
            min_dist = FLT_MAX;
            for(i = 0; i < nclusters; i++) {
                int cluster_base_index = i * nfeatures;
                float ans = 0.0;
                for(j = 0; j < nfeatures; j++) {
                    int addr = point_id + j*npoints;
                    float diff = features[addr] - clusters[cluster_base_index + j];
                    ans += diff*diff;
                }
                if(ans < min_dist) {
                    min_dist = ans;
                    index = i;
                }
            }
            membership[point_id] = index;
        }
    }

    // Reduction for block_deltas and block_clusters is omitted as no GPU reduction is used here.
}


